import os
def get_log_file(filename):
    if '..' in filename or '/' in filename:
        raise SecurityError('Path traversal detected')
    filepath = os.path.abspath(os.path.join('/var/logs/', filename))
    if not filepath.startswith('/var/logs/'):
        raise SecurityError('Outside log directory')
    with open(filepath, 'r') as f:
        return f.read(100)

