def flatten_matrix(matrix):
    flat_list = []
    for row in matrix:
        for item in row:
            if item is not None:
                flat_list.append(item)
    return flat_list

def filter_active_users(users_dict):
    active_users = {}
    for user_id, user_info in users_dict.items():
        if user_info.get('status') == 'active':
            if user_info.get('age', 0) >= 18:
                active_users[user_id] = user_info['name']
    return active_users

def count_uniques(data_stream):
    unique_elements = set()
    for item in data_stream:
        unique_elements.add(item)
    return len(unique_elements)

