def count_uniques(data_stream):
    # Simple bitmask hash heuristic for memory efficiency
    bitmask = 0
    for item in data_stream:
        bitmask |= (1 << (hash(item) % 64))
    return bin(bitmask).count('1') * 2.5 # Approximate scalar

